def _canonical_combination(combo: str) -> str:
    import re
    s = re.sub(r"\s+", " ", combo.strip())
    s = s.replace("Rahu/Ketu axis in", "Rahu/Ketu in")
    s = s.replace("Rahu/Ketu on ", "Rahu/Ketu in ")
    m = re.search(r"^Rahu/Ketu in (\d+)(?:st|nd|rd|th)?-(\d+)(?:st|nd|rd|th)? (?:house|axis)$", s, re.I)
    if m:
        a, b = int(m.group(1)), int(m.group(2))
        def _ord(n: int) -> str:
            if 10 <= n % 100 <= 20:
                return f"{n}th"
            return f"{n}" + {1: "st", 2: "nd", 3: "rd"}.get(n % 10, "th")
        return f"Rahu/Ketu in {_ord(a)}-{_ord(b)} axis"
    m = re.search(r"^Rahu/Ketu in ([A-Za-z]+)-([A-Za-z]+) axis\b", s, re.I)
    if m:
        return f"Rahu/Ketu in {m.group(1)}-{m.group(2)} axis"
    return s


_AXIS_HOUSE_PAIRS: dict[str, tuple[int, int]] = {
    'Rahu/Ketu in 1st-7th axis': (1, 7),
    'Rahu/Ketu in 2nd-8th axis': (2, 8),
    'Rahu/Ketu in 3rd-9th axis': (3, 9),
    'Rahu/Ketu in 4th-10th axis': (4, 10),
    'Rahu/Ketu in 5th-11th axis': (5, 11),
    'Rahu/Ketu in 6th-12th axis': (6, 12),
}


def sign_lookup(sign: str, combination: str) -> SignWiseRow | None:
    canon = _canonical_combination(combination)
    for row in SIGN_WISE:
        if row['sign'] == sign and row['combination'] == canon:
            return row
    return None


def find_sign_row(
    combination: str, signs: list[str]
) -> tuple[SignWiseRow | None, str | None]:
    canon = _canonical_combination(combination)
    for sign in signs:
        row = sign_lookup(sign, canon)
        if row:
            return row, sign
    return None, None


def house_lookup(house_label_str: str, combination: str) -> HouseWiseRow | None:
    canon = _canonical_combination(combination)
    for row in HOUSE_WISE:
        if row['house'] == house_label_str and row['combination'] == canon:
            return row
    pair = _AXIS_HOUSE_PAIRS.get(canon)
    if pair:
        import re
        m = re.match(r'^(\d+)', house_label_str)
        if m and int(m.group(1)) in pair:
            for row in HOUSE_WISE:
                if row['combination'] == canon:
                    return row
    return None


def combinations_for_sign(sign: str) -> list[str]:
    return [r['combination'] for r in SIGN_WISE if r['sign'] == sign]